import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data.get('projects', []):
        pname = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                key = (pname, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)
all_keys = sorted(set(b.keys()) | set(a.keys()))

changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes.append((k, bv, av))
    else:
        unchanged.append((k, bv))

print('=== CHANGES ===')
if changes:
    for (proj, fw, pkg), bv, av in changes:
        print(f'  {proj} [{fw}] {pkg}: {bv} -> {av}')
else:
    print('  None')

print(f'\n=== UNCHANGED ({len(unchanged)} packages) ===')
for (proj, fw, pkg), v in unchanged:
    print(f'  {proj} [{fw}] {pkg}: {v}')
"

